con:config.script:
def base = context.expand('${#Project#baseUrl}')
def token = context.expand('${#Project#bearerToken}')
def conn = new URL("${base}/rest/interviews").openConnection()
conn.setRequestProperty("Authorization", "Bearer ${token}")
assert conn.responseCode == 200 : "Expected 200, got ${conn.responseCode}"
def body = conn.inputStream.text
assert body.contains('"interviews"') : "Response must contain interviews array"
log.info("List interviews: OK")

def base = context.expand('${#Project#baseUrl}')
def token = context.expand('${#Project#bearerToken}')
def conn = new URL("${base}/rest/interviews/INT-001").openConnection()
conn.setRequestProperty("Authorization", "Bearer ${token}")
assert conn.responseCode == 200
def body = conn.inputStream.text
assert body.contains('"INT-001"')
assert body.contains('"candidate"')
log.info("Get interview INT-001: OK")

def base = context.expand('${#Project#baseUrl}')
def conn = new URL("${base}/rest/interviews").openConnection()
assert conn.responseCode == 401 : "Expected 401 without auth, got ${conn.responseCode}"
log.info("No auth returns 401: OK")

def base = context.expand('${#Project#baseUrl}')
def token = context.expand('${#Project#bearerToken}')

// Create
def create = new URL("${base}/rest/interviews").openConnection()
create.requestMethod = "POST"
create.setRequestProperty("Authorization", "Bearer ${token}")
create.setRequestProperty("Content-Type", "application/json")
create.doOutput = true
create.outputStream.write('{"candidateId":"CAND-002","position":"SoapUI Test"}'.bytes)
assert create.responseCode == 201 : "Create: expected 201, got ${create.responseCode}"
def createBody = new groovy.json.JsonSlurper().parseText(create.inputStream.text)
def id = createBody.interview.id
log.info("Created interview: ${id}")

// Update status
def patch = new URL("${base}/rest/interviews/${id}/status").openConnection()
patch.requestMethod = "PATCH"
patch.setRequestProperty("Authorization", "Bearer ${token}")
patch.setRequestProperty("Content-Type", "application/json")
patch.doOutput = true
patch.outputStream.write('{"status":"IN_PROGRESS"}'.bytes)
assert patch.responseCode == 200

// Evaluate
def eval = new URL("${base}/rest/interviews/${id}/evaluate").openConnection()
eval.requestMethod = "POST"
eval.setRequestProperty("Authorization", "Bearer ${token}")
eval.setRequestProperty("Content-Type", "application/json")
eval.doOutput = true
eval.outputStream.write('{"score":82}'.bytes)
assert eval.responseCode == 200
def evalBody = new groovy.json.JsonSlurper().parseText(eval.inputStream.text)
assert evalBody.interview.status == "COMPLETED"
assert evalBody.interview.recommendation == "HIRE"
log.info("Lifecycle complete: ${id} → COMPLETED/HIRE")

def base = context.expand('${#Project#baseUrl}')
def conn = new URL("${base}/soap?wsdl").openConnection()
assert conn.responseCode == 200
def body = conn.inputStream.text
assert body.contains('InterviewMockService')
log.info("WSDL available: OK")
